import { defineStore } from "pinia";

export const useFilesStore = defineStore("files", {
  state: () => ({
    files: JSON.parse(localStorage.getItem("uploadedFiles")) || [],
  }),

  getters: {
    getAllFiles: (state) => state.files,
    getPdfFiles: (state) => state.files.filter((f) => f.type === "pdf"),
    getImageFiles: (state) => state.files.filter((f) => f.type === "image"),
  },

  actions: {
    addFile(file) {
      const newFile = {
        id: Date.now().toString(),
        uploadedAt: new Date().toISOString(),
        ...file,
      };
      this.files.push(newFile);
      this.saveToStorage();
      return newFile;
    },

    deleteFile(id) {
      const index = this.files.findIndex((f) => f.id === id);
      if (index !== -1) {
        this.files.splice(index, 1);
        this.saveToStorage();
        return true;
      }
      return false;
    },

    saveToStorage() {
      localStorage.setItem("uploadedFiles", JSON.stringify(this.files));
    },
  },
});
