import { defineStore } from "pinia";

// بيانات الأدمن
const ADMIN_DATA = {
  email: "admin@eduplatform.com",
  password: "admin123",
  name: "مدير النظام",
  role: "admin",
};

// بيانات الأستاذ
const TEACHER_DATA = {
  email: "momenwawi20@gmail.com",
  password: "420422370",
  name: "الأستاذ",
  role: "teacher",
};

// مفتاح التخزين للطلاب
const STUDENTS_STORAGE_KEY = "edu_platform_students";

// استرجاع الطلاب من localStorage
const getStoredStudents = () => {
  const stored = localStorage.getItem(STUDENTS_STORAGE_KEY);
  return stored ? JSON.parse(stored) : [];
};

// حفظ الطلاب في localStorage
const saveStudents = (students) => {
  localStorage.setItem(STUDENTS_STORAGE_KEY, JSON.stringify(students));
};

export const useAuthStore = defineStore("auth", {
  state: () => ({
    user: JSON.parse(localStorage.getItem("user")) || null,
    isLoggedIn: !!localStorage.getItem("user"),
    students: getStoredStudents(),
  }),

  actions: {
    login(email, password) {
      // تحقق من بيانات الأدمن
      if (email === ADMIN_DATA.email && password === ADMIN_DATA.password) {
        this.user = {
          email: ADMIN_DATA.email,
          name: ADMIN_DATA.name,
          role: ADMIN_DATA.role,
        };
        this.isLoggedIn = true;
        localStorage.setItem("user", JSON.stringify(this.user));
        return { success: true, role: "admin" };
      }

      // تحقق من بيانات الأستاذ
      if (email === TEACHER_DATA.email && password === TEACHER_DATA.password) {
        this.user = {
          email: TEACHER_DATA.email,
          name: TEACHER_DATA.name,
          role: TEACHER_DATA.role,
        };
        this.isLoggedIn = true;
        localStorage.setItem("user", JSON.stringify(this.user));
        return { success: true, role: "teacher" };
      }

      // تحقق من بيانات الطلاب
      const student = this.students.find(
        (s) => s.email === email && s.password === password
      );
      if (student) {
        this.user = {
          id: student.id,
          email: student.email,
          name: student.name,
          role: student.role,
        };
        this.isLoggedIn = true;
        localStorage.setItem("user", JSON.stringify(this.user));
        return { success: true, role: "student" };
      }

      return {
        success: false,
        message: "البريد الإلكتروني أو كلمة المرور غير صحيحة",
      };
    },

    logout() {
      this.user = null;
      this.isLoggedIn = false;
      localStorage.removeItem("user");
    },

    // إضافة طالب جديد
    addStudent(studentData) {
      const newStudent = {
        id: Date.now().toString(),
        email: studentData.email,
        password: studentData.password,
        name: studentData.name,
        role: "student",
        createdAt: new Date().toISOString(),
      };
      this.students.push(newStudent);
      saveStudents(this.students);
      return newStudent;
    },

    // تحديث بيانات طالب
    updateStudent(id, studentData) {
      const index = this.students.findIndex((s) => s.id === id);
      if (index !== -1) {
        this.students[index] = { ...this.students[index], ...studentData };
        saveStudents(this.students);
        return true;
      }
      return false;
    },

    // حذف طالب
    deleteStudent(id) {
      this.students = this.students.filter((s) => s.id !== id);
      saveStudents(this.students);
    },

    // الحصول على قائمة الطلاب
    getStudents() {
      return this.students;
    },

    // تحميل الطلاب من التخزين
    loadStudents() {
      this.students = getStoredStudents();
    },
  },
});
