import { defineStore } from "pinia";

export const useExamsStore = defineStore("exams", {
  state: () => ({
    exams: JSON.parse(localStorage.getItem("exams")) || [],
    results: JSON.parse(localStorage.getItem("examResults")) || [],
    // حالة الامتحان الجاري لكل طالب
    ongoingExams: JSON.parse(localStorage.getItem("ongoingExams")) || {},
  }),

  getters: {
    getAllExams: (state) => state.exams,
    getActiveExams: (state) => state.exams.filter((e) => e.isActive),
    getExamById: (state) => (id) => state.exams.find((e) => e.id === id),
    getResultsByExam: (state) => (examId) =>
      state.results.filter((r) => r.examId === examId),
    getResultsByStudent: (state) => (studentEmail) =>
      state.results.filter((r) => r.studentEmail === studentEmail),
    hasStudentTakenExam: (state) => (examId, studentEmail) => {
      return state.results.some(
        (r) => r.examId === examId && r.studentEmail === studentEmail
      );
    },
    // الحصول على حالة الامتحان الجاري للطالب
    getOngoingExam: (state) => (examId, studentEmail) => {
      const key = `${examId}_${studentEmail}`;
      return state.ongoingExams[key] || null;
    },
  },

  actions: {
    createExam(exam) {
      const newExam = {
        id: Date.now().toString(),
        createdAt: new Date().toISOString(),
        isActive: true,
        ...exam,
      };
      this.exams.push(newExam);
      this.saveExamsToStorage();
      return newExam;
    },

    updateExam(id, updates) {
      const index = this.exams.findIndex((e) => e.id === id);
      if (index !== -1) {
        this.exams[index] = { ...this.exams[index], ...updates };
        this.saveExamsToStorage();
        return true;
      }
      return false;
    },

    toggleExamStatus(id) {
      const exam = this.exams.find((e) => e.id === id);
      if (exam) {
        exam.isActive = !exam.isActive;
        this.saveExamsToStorage();
        return true;
      }
      return false;
    },

    deleteExam(id) {
      const index = this.exams.findIndex((e) => e.id === id);
      if (index !== -1) {
        this.exams.splice(index, 1);
        this.saveExamsToStorage();
        return true;
      }
      return false;
    },

    // توليد أسئلة عشوائية للامتحان
    getRandomizedQuestions(examId) {
      const exam = this.exams.find((e) => e.id === examId);
      if (!exam) return [];

      // خلط الأسئلة عشوائياً
      const shuffled = [...exam.questions].sort(() => Math.random() - 0.5);

      // خلط الخيارات لكل سؤال اختيار من متعدد
      return shuffled.map((q) => {
        if (q.type === "multiple" && q.options) {
          const shuffledOptions = [...q.options].sort(
            () => Math.random() - 0.5
          );
          return { ...q, options: shuffledOptions };
        }
        return q;
      });
    },

    // بدء أو استكمال امتحان
    startOrResumeExam(examId, studentEmail) {
      const key = `${examId}_${studentEmail}`;
      const existing = this.ongoingExams[key];

      if (existing) {
        // التحقق من انتهاء الوقت
        const elapsedSeconds = Math.floor(
          (Date.now() - existing.startTime) / 1000
        );
        const remainingTime = existing.totalDuration - elapsedSeconds;

        if (remainingTime <= 0) {
          // انتهى الوقت، يجب تسليم الامتحان تلقائياً
          return { ...existing, timeRemaining: 0, expired: true };
        }

        return { ...existing, timeRemaining: remainingTime, expired: false };
      }

      // بدء امتحان جديد
      const exam = this.exams.find((e) => e.id === examId);
      if (!exam) return null;

      const questions = this.getRandomizedQuestions(examId);
      const newOngoing = {
        examId,
        studentEmail,
        questions,
        answers: {},
        currentQuestionIndex: 0,
        startTime: Date.now(),
        totalDuration: exam.duration * 60, // بالثواني
        timeRemaining: exam.duration * 60,
      };

      this.ongoingExams[key] = newOngoing;
      this.saveOngoingExamsToStorage();

      return { ...newOngoing, expired: false };
    },

    // تحديث حالة الامتحان الجاري
    updateOngoingExam(examId, studentEmail, updates) {
      const key = `${examId}_${studentEmail}`;
      if (this.ongoingExams[key]) {
        this.ongoingExams[key] = { ...this.ongoingExams[key], ...updates };
        this.saveOngoingExamsToStorage();
      }
    },

    // حفظ الإجابة
    saveAnswer(examId, studentEmail, questionId, answer) {
      const key = `${examId}_${studentEmail}`;
      if (this.ongoingExams[key]) {
        this.ongoingExams[key].answers[questionId] = answer;
        this.saveOngoingExamsToStorage();
      }
    },

    // حفظ السؤال الحالي
    saveCurrentQuestion(examId, studentEmail, index) {
      const key = `${examId}_${studentEmail}`;
      if (this.ongoingExams[key]) {
        this.ongoingExams[key].currentQuestionIndex = index;
        this.saveOngoingExamsToStorage();
      }
    },

    // إنهاء الامتحان الجاري
    finishOngoingExam(examId, studentEmail) {
      const key = `${examId}_${studentEmail}`;
      delete this.ongoingExams[key];
      this.saveOngoingExamsToStorage();
    },

    submitExamResult(result) {
      const newResult = {
        id: Date.now().toString(),
        submittedAt: new Date().toISOString(),
        ...result,
      };
      this.results.push(newResult);
      this.saveResultsToStorage();

      // إزالة الامتحان الجاري
      this.finishOngoingExam(result.examId, result.studentEmail);

      return newResult;
    },

    saveExamsToStorage() {
      localStorage.setItem("exams", JSON.stringify(this.exams));
    },

    saveResultsToStorage() {
      localStorage.setItem("examResults", JSON.stringify(this.results));
    },

    saveOngoingExamsToStorage() {
      localStorage.setItem("ongoingExams", JSON.stringify(this.ongoingExams));
    },
  },
});
