import { defineStore } from "pinia";

export const useQuestionsStore = defineStore("questions", {
  state: () => ({
    questions: JSON.parse(localStorage.getItem("questions")) || [],
  }),

  getters: {
    getAllQuestions: (state) => state.questions,
    getMultipleChoiceQuestions: (state) =>
      state.questions.filter((q) => q.type === "multiple"),
    getTrueFalseQuestions: (state) =>
      state.questions.filter((q) => q.type === "truefalse"),
    getQuestionById: (state) => (id) =>
      state.questions.find((q) => q.id === id),
  },

  actions: {
    addQuestion(question) {
      const newQuestion = {
        id: Date.now().toString(),
        createdAt: new Date().toISOString(),
        ...question,
      };
      this.questions.push(newQuestion);
      this.saveToStorage();
      return newQuestion;
    },

    updateQuestion(id, updates) {
      const index = this.questions.findIndex((q) => q.id === id);
      if (index !== -1) {
        this.questions[index] = { ...this.questions[index], ...updates };
        this.saveToStorage();
        return true;
      }
      return false;
    },

    deleteQuestion(id) {
      const index = this.questions.findIndex((q) => q.id === id);
      if (index !== -1) {
        this.questions.splice(index, 1);
        this.saveToStorage();
        return true;
      }
      return false;
    },

    saveToStorage() {
      localStorage.setItem("questions", JSON.stringify(this.questions));
    },
  },
});
